What is the number of square units in the area of the hexagon below?

[asy]
unitsize(0.5cm);
defaultpen(linewidth(0.7)+fontsize(10));
dotfactor = 4;
int i,j;
for(i=0;i<=4;++i)

{

for(j=-3;j<=3;++j)

{

dot((i,j));

}

}

for(i=1;i<=4;++i)

{

draw((i,-1/3)--(i,1/3));

}
for(j=1;j<=3;++j)

{

draw((-1/3,j)--(1/3,j));

draw((-1/3,-j)--(1/3,-j));

}

real eps = 0.2;

draw((3,3.5+eps)--(3,3.5-eps));
draw((4,3.5+eps)--(4,3.5-eps));
draw((3,3.5)--(4,3.5));

label("1 unit",(3.5,4));

draw((4.5-eps,2)--(4.5+eps,2));
draw((4.5-eps,3)--(4.5+eps,3));
draw((4.5,2)--(4.5,3));

